"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[4714],{2081(e,t,o){o.r(t),o.d(t,{assets:()=>r,contentTitle:()=>h,default:()=>u,frontMatter:()=>i,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-20","title":"Discourses \u2014 Book 2, Chapter 20","description":"Book 2 \u2014 Chapter 20","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-20.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-20","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-20","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":21,"frontMatter":{"sidebar_position":21,"title":"Discourses \u2014 Book 2, Chapter 20","sidebar_label":"Book 2, Ch. 20"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 19","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-19"},"next":{"title":"Book 2, Ch. 21","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21"}}');var n=o(4848),a=o(8453);const i={sidebar_position:21,title:"Discourses \u2014 Book 2, Chapter 20",sidebar_label:"Book 2, Ch. 20"},h="Discourses",r={},d=[{value:"Book 2 \u2014 Chapter 20",id:"book-2--chapter-20",level:2},{value:"Against Followers Of Epicurus And Of The Academy",id:"against-followers-of-epicurus-and-of-the-academy",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,a.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(t.h2,{id:"book-2--chapter-20",children:"Book 2 \u2014 Chapter 20"}),(0,n.jsx)(t.h3,{id:"against-followers-of-epicurus-and-of-the-academy",children:"Against Followers Of Epicurus And Of The Academy"})]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.p,{children:"A philosophical demolition of positions that undermine themselves. The Academic who says nothing is knowable must claim to know that. The Epicurean who says there is no natural human fellowship writes books, lights lamps late into the night, rises early, and labors to persuade strangers \u2014 behavior that makes no sense if he actually believed his own doctrine."}),(0,n.jsx)(t.p,{children:"Epictetus's deeper point: you cannot cut off human nature. Epicurus, for all his theory, kept behaving as a man \u2014 he cared, he wrote, he tried to benefit others. Nature compelled him even as he denied it, just as the Furies compelled Orestes. The Academics keep using their senses while arguing that senses can't be trusted. The fantasy of the chapter \u2014 a slave serving vinegar when asked for gruel and oil when asked for ointment, citing Skeptical principles \u2014 captures the absurdity."}),(0,n.jsx)(t.p,{children:"The closing is the most serious part: these positions, propagated to the young, give cover to the adulterer, the embezzler, the man who neglects his parents. The damage isn't abstract. This is why Epictetus's tone here is less patient than usual \u2014 not intellectual sparring but a genuine assessment of what these doctrines do when they escape the seminar room."})]}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(t.h2,{id:"text",children:"Text"}),(0,n.jsx)(t.p,{children:"EVEN those who contradict propositions that are true and evident are obliged to make use of them. And indeed one may almost give as the strongest proof that a thing is evident that even he who contradicts it finds himself obliged to make use of it. For instance, if one should deny that any universal statement is true, plainly he cannot help asserting the contrary."}),(0,n.jsx)(t.p,{children:"'No universal statement is true.'"}),(0,n.jsx)(t.p,{children:"Slave, this is not true either: for what else is your assertion than, 'If a statement is universal, it is false?' Again, if one comes forward and says, 'Know that nothing is knowable, but that everything is unprovable,' or another says, 'Believe me, and it will be to your advantage; you ought not to believe a man at all'; or again, if another says, 'Learn from me, man, that it is impossible to learn anything; I tell you this, and will teach you, if you will.' What difference is there between such persons and--whom shall I say?--those who call themselves Academics? 'Men, give your assent to the statement that no man assents!'"}),(0,n.jsx)(t.p,{children:"'Believe us that no man believes any one!'"}),(0,n.jsx)(t.p,{children:"So too Epicurus, when he wishes to get rid of the natural fellowship of men with one another, makes use of the very principle of which he is getting rid. For what does he say? 'Men, be not deceived, be not misled or deluded. There is no natural fellowship of rational beings with one another: believe me. Those who state the contrary deceive you and mislead your reason.'"}),(0,n.jsx)(t.p,{children:"What concern, then, is it of yours? Let us be deceived. Will you come off any the worse if the rest of us are all convinced that we have a natural fellowship with one another and that we are bound by all means to guard it? Nay, your position will be much better and more secure. Man, why do you take thought for our sake, why do you keep awake for us, why do you light your lamp, why do you rise early, why do you write such big books? Is it to prevent any of us being deluded into thinking that the gods have any care for mankind, or to prevent us from supposing that the nature of the good is anything but pleasure? For if this is so, be off with you and go to sleep; do as the worm does,"}),(0,n.jsx)(t.p,{children:"for this is the life of which you pronounce yourself worthy: eating, drinking, copulation, evacuation, and snoring."}),(0,n.jsx)(t.p,{children:"What does it matter to you, what opinions others will hold on these matters, or whether they are right or wrong? What have we to do with you? You take interest in sheep because they offer themselves to be shorn and milked and finally to be slaughtered by us. Would it not be desirable if men could be charmed and bewitched by the Stoics into slumber, and offer themselves to you and those like you to be shorn and milked? These sentiments were proper enough to utter to your fellow Epicureans; ought you not to conceal them from outsiders, and take special pains to convince them before all things that we are born with a sociable nature, that self-control is a good thing, that so you may secure everything for yourself? Or do you say we must maintain this fellowship towards some and not towards others? Towards whom, then, must we observe it? Towards those who observe it in their turn, or towards those who transgress it? And who transgress it more completely than you who have laid down these doctrines?"}),(0,n.jsx)(t.p,{children:"What, then, was it that roused Epicurus from his slumbers and compelled him to write what he wrote? What else but that which is the most powerful of all human things, Nature, which draws a man to her will though he groan and resist? For (she says), because you hold these unsociable opinions, write them down and bequeath them to others and stay up late for them and by your own act accuse the very principles you maintain. What! we speak of Orestes pursued by the Furies and roused from his slumbers, but are not the Furies and Torments that beset Epicurus more exacting? They roused him from his sleep and would not allow him to rest, but compelled him to announce his miseries, as madness and wine compel the priests of Cybele. So powerful and unconquerable a thing is human nature. How can a vine be moved to act, not as a vine but as an olive, or again an olive not as an olive but as a vine? It is impossible, inconceivable. So it is impossible for man utterly to destroy the instincts of man; even those who have their bodily organs cut off cannot cut off the desires of men. In the same way Epicurus, though he cut off all the attributes of a man and a householder and a citizen and a friend, could not cut off human desires. No, he could not do it, any more than the indolent Academics could cast away or blind their senses, though they have made this the chief object of their life. Is not this sheer misfortune?  A man has received from Nature measures and standards for the discovery of truth, and instead of busying himself to add to them and to work out further results, he does exactly the opposite, and tries to remove and destroy any faculty which he possesses for discovering the truth."}),(0,n.jsx)(t.p,{children:"What say you, philosopher? What is your view of religion and piety?"}),(0,n.jsx)(t.p,{children:"'If you will, I will prove that it is good.'"}),(0,n.jsx)(t.p,{children:"Prove it then, that our fellow citizens may take heed and honour the Divine and cease at last from being indifferent as to the highest matters."}),(0,n.jsx)(t.p,{children:"'Have you the proofs then?'"}),(0,n.jsx)(t.p,{children:"I have, and am thankful for it!"}),(0,n.jsx)(t.p,{children:"'Since you find such an interest in these things, now hear the contrary: \"The gods do not exist, and if they do, they pay no regard to men and we have no communion with them, and thus religion and piety, of which the multitude talk, are a lie of pretentious persons and sophists, or it may be of lawgivers, for the fear and deterrence of wrongdoers.\"'"}),(0,n.jsx)(t.p,{children:"Bravo, philosopher! What a service you confer on our citizens! Our young men are already inclining to despise divine things, and you recover them for us!"}),(0,n.jsx)(t.p,{children:'\'What is the matter? Does not this please you? Now learn, how justice is nothing, how self-respect is folly, how "father" and "son" are empty words.\''}),(0,n.jsx)(t.p,{children:"Bravo, philosopher! Stick to your task, persuade our young men, that we may have more to agree with you and share your views. These, no doubt, are the arguments which have brought well-governed cities to greatness, these are the arguments which made Lacedaemon, these are the convictions which Lycurgus wrought into the Spartans by his laws and training: that slavery is no more shameful than noble, and freedom no more noble than shameful! For these beliefs no doubt those who died at Thermopylae died! And for what principles but these did the Athenians give up their city?"}),(0,n.jsx)(t.p,{children:"And yet the men who state these theories marry and beget children and share in city life and appoint themselves priests and prophets. Of what? Of what has no existence! And they question the Pythian prophetess themselves, to learn lies, and they interpret oracles to others. Is not this the height of shameless imposition?"}),(0,n.jsx)(t.p,{children:"Man, what are you doing? You convict yourself of falsehood day by day: will you not abandon these crude fallacies? When you eat where do you put your hand, to your mouth or to your eye? When you bathe into what do you go? When did you ever call the jug a saucer or the ladle a spit?"}),(0,n.jsx)(t.p,{children:"If I were slave to one of these men, I would torture him, even if I had to stand a flogging from him every day. Put a drop of oil, boy, in the bath.' I would get some fish sauce and pour it over his head. 'What is that? By your fortune I had an impression, very like oil, indistinguishable from it. 'Give me gruel here.' I would fill a dish with vinegar sauce and bring it him."}),(0,n.jsx)(t.p,{children:"'Did I not ask for gruel?'"}),(0,n.jsx)(t.p,{children:"Yes, master, this is gruel."}),(0,n.jsx)(t.p,{children:"'Is not this vinegar sauce?'"}),(0,n.jsx)(t.p,{children:"How is it more that than gruel?"}),(0,n.jsx)(t.p,{children:"'Take it and smell, take it and taste.'"}),(0,n.jsx)(t.p,{children:"How can you know if the senses play us false? If I had three or four fellow slaves who shared my mind I should give him such a dressing that he would hang himself, or change his opinion. Such men trifle with us; they take advantage of all the gifts of nature, while in theory they do away with them."}),(0,n.jsx)(t.p,{children:"Grateful and self-respecting men indeed! they eat bread every day, to say nothing else, and yet dare to assert that we know not whether there is a Demeter or Kore or Pluto: not to say that they enjoy day and night and the changes of the year, the stars and sea and land and the service that men render, yet not one of these things makes them take notice in the least. No, their only aim is to vomit their paltry problem, and having thus exercised their stomach to go away and have a bath. But they have not given the slightest thought to what they are going to say: what subject they are going to speak about, or to whom, and what they are going to get from these arguments: whether any young man of noble spirit may be influenced by them or has been influenced already and may lose all the germs of nobility in him: whether we may be giving an adulterer opportunity to brazen out his acts: whether one who is embezzling public funds may find some excuse to lay hold of in these theories: whether one who neglects his parents may get from them fresh courage."}),(0,n.jsx)(t.p,{children:"What, then, do you hold good or evil, base or noble? Is it this doctrine, or that? It is useless to go on disputing with one of these men, or reasoning with him, or trying to alter his opinion. One might have very much more hope of altering the mind of a profligate than of men who are absolutely deaf and blind to their own miseries."})]})]})}function u(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>i,x:()=>h});var s=o(6540);const n={},a=s.createContext(n);function i(e){const t=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:i(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);